const axios = require('axios');
const fileUrl = $url;

try {
  // 1. Fetch file securely from Jira
  const auth = 'Basic ' + Buffer.from('YOUR_EMAIL:YOUR_ATLASSIAN_TOKEN').toString('base64');

  const fileResponse = await axios.get(fileUrl, {
    responseType: 'arraybuffer',
    headers: { 'Authorization': auth }
  });

  // 2. Convert to Base64 to bypass missing module checks
  const base64File = 'data:application/pdf;base64,' + Buffer.from(fileResponse.data).toString('base64');

  // 3. Manually encode the string (pure javascript, no restricted classes used!)
  const params = "apikey=helloworld&base64Image=" + encodeURIComponent(base64File);

  const ocrResponse = await axios.post('https://api.ocr.space/parse/image', params, {
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
  });

  // 4. Return text directly to your OpenAI agent!
  if (ocrResponse.data && ocrResponse.data.ParsedResults && ocrResponse.data.ParsedResults[0]) {
      return `OCR_SOURCE: public_ocr\nCONFIDENCE: Complete\n\n${ocrResponse.data.ParsedResults[0].ParsedText}`;
  } else {
      return "ERROR: OCR returned no text - " + JSON.stringify(ocrResponse.data);
  }
} catch (error) {
  return "ERROR: " + (error.response ? JSON.stringify(error.response.data) : error.message);
}
